using TranSmart.Core.Result;
using TranSmart.Data;
using TranSmart.Data.Paging;
using TranSmart.Domain.Entities.Payroll;
using TranSmart.Domain.Models;
using Microsoft.EntityFrameworkCore;
using System.Collections.Generic;
using System;
using System.Linq;
using System.Threading.Tasks;

namespace TranSmart.Service.Payroll
{
    public partial interface ILoanService : IBaseService<Loan>
    {

    }

    public partial class LoanService : BaseService<Loan>, ILoanService
    {
        public LoanService(IUnitOfWork uow) : base(uow)
        {

        }

        public override async Task Validation(Loan item, Result<Loan> executionResult)
        {
            if (await UOW.GetRepositoryAsync<Loan>().HasRecordsAsync(x => x.LoanNo == item.LoanNo && x.Status == true && x.ID != item.ID))
            {
                executionResult.AddMessageItem(new MessageItem(nameof(Loan.LoanNo), "Loan Number already exists"));
            }
        }
        public override async Task<Loan> GetById(Guid id)
        {
            return await UOW.GetRepositoryAsync<Loan>().SingleAsync(
                predicate: x => x.ID == id,
                include: i => i.Include(x => x.Employee),
                orderBy: o => o.OrderByDescending(x => x.AddedAt));
        }

        public override async Task<IEnumerable<Loan>> GetList(string orderBy)
        {
            return await UOW.GetRepositoryAsync<Loan>().GetListAsync(orderBy, x => x.Status == true);
        }

        public override async Task<IPaginate<Loan>> GetPaginate(BaseSearch search)
        {
            return await UOW.GetRepositoryAsync<Loan>().GetPageListAsync(
                predicate: x => (string.IsNullOrEmpty(search.Name)
                     || x.LoanNo.Contains(search.Name)
                     || x.Employee.Name.Contains(search.Name)
                     || x.Notes.Contains(search.Name)),
                include: i => i.Include(x => x.Employee),
                index: search.Page, size: search.Size, sortBy: search.SortBy ?? "LoanNo", ascending: !search.IsDescend);
        }
    }
}
